document.addEventListener("DOMContentLoaded",function(){processMarkHighlights()});function processMarkHighlights(){const e=document.querySelectorAll(".content-wrapper p, .content-wrapper li, .content-wrapper blockquote");e.forEach(e=>{let t=e.innerHTML;const n=/==([^=]+)==/g;t=t.replace(n,'<span class="mark-highlight">$1</span>');const s=/~~~([^~]+)~~~/g;t=t.replace(s,'<span class="hidden-text">$1</span>'),e.innerHTML=t})}